import { readFileSync } from 'fs'
import { resolve } from 'path'
import { beforeAll, describe, expect, test } from 'vitest'
import { SignMemeDataInPlace, SignWithMemeCrypto } from '../encryption/Encryption'
import { bytesBeHexString, MemeKey, pokedexAndSaveFileMemeKey } from '../encryption/MemeKey'
import { Gen7AlolaSave } from '../Gen7AlolaSave'
import { get16BitChecksumLittleEndian } from '../util/byteLogic'
import { PathData } from '../util/path'
import { initializeWasm } from './init'

beforeAll(initializeWasm)

describe('gen 7 save files', () => {
  let ultraSunSave: Gen7AlolaSave
  let saveBytes: Uint8Array

  beforeAll(() => {
    const savePath = resolve(__dirname, 'save-files/ultrasun')

    saveBytes = new Uint8Array(readFileSync(savePath))

    const parsedPath: PathData = {
      raw: 'save-files/ultrasun',
      name: 'ultrasun',
      dir: 'save-files',
      ext: '',
      separator: '/',
    }

    ultraSunSave = new Gen7AlolaSave(parsedPath, saveBytes)
  })

  test('should have expected trainer name', () => {
    expect(ultraSunSave.name).toBe('RoC')
  })

  test('first mon is as expected', () => {
    expect(ultraSunSave.boxes[0].boxSlots[0]?.nickname === 'Bulbasaur')
  })
})

describe('moon save file', () => {
  let moonSav: Gen7AlolaSave
  let saveBytes: Uint8Array

  beforeAll(() => {
    const savePath = resolve(__dirname, 'save-files/moon')

    saveBytes = new Uint8Array(readFileSync(savePath))

    const parsedPath: PathData = {
      raw: 'save-files/moon',
      name: 'moon',
      dir: 'save-files',
      ext: '',
      separator: '/',
    }

    moonSav = new Gen7AlolaSave(parsedPath, saveBytes)
  })

  test('should have expected trainer name', () => {
    expect(moonSav.name).toBe('RoC')
  })

  test('output of to_bytes doesnt change', () => {
    const writer = moonSav.prepareWriter()
    expect(get16BitChecksumLittleEndian(writer.bytes.buffer, 0, writer.bytes.length)).toBe(0x3065)
  })

  test('first mon is as expected', () => {
    expect(moonSav.boxes[0].boxSlots[0]?.nickname === 'Bulbasaur')
  })
})

describe('meme key', () => {
  let saveBytes: Uint8Array

  beforeAll(() => {
    const savePath = resolve(__dirname, 'save-files/moon')

    saveBytes = new Uint8Array(readFileSync(savePath))
  })

  test('meme key values are accurate', () => {
    const memeKey = new MemeKey(saveBytes)
    expect(memeKey.getPrivateKeyU16()).toBe(
      '775455668fff3cba3026c2d0b26b8085895958341157aeb03b6b0495ee57803e2186eb6cb2eb62a71df18a3c9c6579077670961b3a6102dabe5a194ab58c3250aed597fc78978a326db1d7b28dcccb2a3e014edbd397ad33b8f28cd525054251'
    )
    expect(memeKey.getPublicKeyU16()).toBe('5224')
    expect(memeKey.getModU16()).toBe(
      'd9040000fb0400000e28000008280000de0400003b060000da0400005ec800000628000056130000f50400001e060000ee0400004e5b01005b14000007300000f304000057070000c0060000f90400000f2800005918000053200000ef04000028'
    )
  })

  test('meme key aes encrypt', () => {
    const memeKey = new MemeKey(pokedexAndSaveFileMemeKey)
    expect(memeKey.getAesEncryptedFirst100Hex(saveBytes)).toBe(
      '2d0070051d0070054d007004dd007000cd007004ed00700d9040000fb0400000e28000008280000de0400003b060000da0400005ec800000628000056130000f50400001e060000ee0400004e5b01005b14000007300000f304000057070000c0060000'
    )
  })

  // only using the first 1000 bytes, because creating a hex string using the output of the whole save file results in an enormous string that takes forever to build

  test('rsa public key', () => {
    const memeKey = new MemeKey(pokedexAndSaveFileMemeKey)
    expect(memeKey.getRsaPublicHex(saveBytes.slice(0, 1000))).toBe(
      '2aba82bedb9bf467703ab8047adb8179614ec3e5467da6a63eb9fa05e4bdbc2eea3e1c24d3080fc9ceebb5a29957ec6d7b39cdcaf3ad0d0425a139c23f893205b130150a01d40307e3db93700afbb7481927ffaff89631f7d93d8f5595328e21'
    )
  })

  test('rsa private key', () => {
    const memeKey = new MemeKey(pokedexAndSaveFileMemeKey)
    expect(memeKey.getRsaPrivateHex(saveBytes.slice(0, 1000))).toBe(
      '1fd81da0c10c63dcf3cbd1d0703190477736ee9cdba46ce8dee9bcaeace1457f79b0ffd9ea8031f60c56ccacc8acdea4c7bc54e540308673e35c15d1b907034627fb65a427d7f4b1ff2b6c84e6058698ac62dd66b74db21c7c301bf55d9e5fde'
    )
  })

  test('sign meme data in place', () => {
    const signed = SignMemeDataInPlace(saveBytes.slice(0, 1000))
    expect(bytesBeHexString(signed)).toBe(
      ''
    )
  })

  test('sign with meme crypto last 1000 bytes', () => {
    const signed = SignWithMemeCrypto(saveBytes)
    expect(bytesBeHexString(signed.slice(-1000))).toBe(
      ''
    )
  })
})
